import React, { useEffect, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../contexts/AuthContext";
import { toast } from "sonner";

export default function EmergentCallback() {
  const { emergentSession } = useAuth();
  const nav = useNavigate();
  const [error, setError] = useState(null);
  const ran = useRef(false);

  useEffect(() => {
    if (ran.current) return;
    ran.current = true;
    // Emergent returns session_id in the URL fragment: #session_id=...
    const hash = window.location.hash || "";
    const match = hash.match(/session_id=([^&]+)/);
    const sessionId = match ? decodeURIComponent(match[1]) : null;
    if (!sessionId) {
      setError("missing session_id in callback");
      return;
    }
    (async () => {
      try {
        await emergentSession(sessionId);
        toast.success("signed in with google");
        // clear fragment
        window.history.replaceState(null, "", "/dashboard");
        nav("/dashboard");
      } catch (e) {
        setError(e?.response?.data?.detail || "google sign-in failed");
      }
    })();
  }, [emergentSession, nav]);

  return (
    <div className="min-h-screen bg-black text-white flex items-center justify-center px-6">
      <div className="text-center">
        {error ? (
          <>
            <p className="text-2xl mb-2" data-testid="emergent-error">sign-in failed</p>
            <p className="text-white/60 text-sm mb-4">{error}</p>
            <button onClick={() => nav("/login")} className="text-sm underline">back to login</button>
          </>
        ) : (
          <p className="text-white/70 text-sm" data-testid="emergent-loading">completing google sign-in…</p>
        )}
      </div>
    </div>
  );
}
